_UNWIRED_STORES: tuple[str, ...] = ("proposals", "verdicts", "observations", "telemetry")

# The per-store Σ tag (§2.7 vocabulary; `core/scope.py` Stratum forest). A library-level DEFAULT:
# the note under-specifies the exact per-store mapping (the Σ-gated View wrapper is parked, plan
# §11), so this is a documented default, refinable by the View layer without re-deriving the spine.
# eval keeps its OWN Σ (§2.9-1: its own stratum, non-promotable, ∉ MIRROR_READABLE).
_STRATUM: dict[str, str] = {
    "versions": "mirror",
    "catalog": "mirror",
    "edges": "interpreted",
    "derived": "interpreted",
    "runledger": "ops",
    "attestations": "ops",
    "eval": "eval",
}

# The certificate(s) each stratum requires for a cut to be sound (note §2.4; plan §8 "certificates
# for all strata whose stores intersect the frontier"). GROUNDED, a spec-fidelity resolution the
# note under-specifies as an exact map (finding-0095):
#   * mirror (versions/catalog = the repo-backed corpus) → COMMIT — the ratified `_CUT_CLOCKS` case:
#     the commit SHA IS the cut for repo-backed strata (`core/scope.py:450`).
#   * ops (runledger/attestations) + interpreted (edges/derived) = core stores written by scheduler
#     jobs that can incorporate in-flight edge observations → TROUGH (no in-flight core causality)
#     AND HANDOFF (no in-flight edge↔core flow). A cut across the core↔edge boundary needs both.
#   * eval (eval results) = internal scheduler jobs, no edge dependency → TROUGH.
# The FULL cross-strata cut (all four) therefore composes {COMMIT, TROUGH, HANDOFF} — exactly the
# note's "commit ∧ trough-empty ∧ handoff-empty" (§2.4).
_STRATUM_CERTIFICATES: dict[str, frozenset[Certificate]] = {
    "mirror": frozenset({Certificate.COMMIT}),
    "ops": frozenset({Certificate.TROUGH, Certificate.HANDOFF}),
    "interpreted": frozenset({Certificate.TROUGH, Certificate.HANDOFF}),
    "eval": frozenset({Certificate.TROUGH}),
}

# The handoff-empty observable — MIRRORED (not imported) from `core/sensing.py:63-64`, the zone-
# boundary discipline: the sealed core and the edge share "nothing but the async file handoff …
# mirrored-not-imported wire shapes" (note §2.1-1). Both dirs empty ⇒ no in-flight edge↔core flow.
_HANDOFF_SUBDIRS: tuple[str, ...] = ("requests", "observations")


def _event_id(store: str, chain_key: str, position: int | None) -> str:
    """Deterministic, content-free event id. Chain-less events render position as '-'."""
    return f"{store}:{chain_key}:{position if position is not None else '-'}"


# ── GC-2 · the clock maps (plan §6; note §2.3 laws C1–C4) ────────────────────────────────────────
# The registered clocks (`core/scope.py:171-184`, READ-ONLY here) partition by how their p_κ is
# sourced against the materialized spine (= N):
#   * N              — identity: p_N(e) = e (the finest clock, the spine itself). Singleton fibers.
#   * N_S            — per-stratum event tick: p(N_S, e) = (stratum, e). The RICH N_s object (the
#                      restriction with its induced order + proper time) is `Spine.n_s(stratum)`.
#   * read-clocks    — projection_event / last_write / now: mint NO events; their tick is the
#                      BORROWED per-store frontier (Law C3). p(read,e) = frontier_at(e.store).
#   * WALL           — Law C4: generates nothing; p/fiber RAISE. No p_wall exists (structural).
#   * COMMIT /       — repo-backed COARSENINGS ("a commit is a RANGE of N"). Their tick is which git
#     DISTINCT_       commit / content-snapshot an event belongs to — sourced EXTERNALLY: no store
#     SNAPSHOT        spine enumerates carries a commit SHA, and `core/` never shells to git (§2.10:
#                     the spine is arithmetic over stores, opens no socket). So the tick is INJECTED
#                     (`coarsening_ticks`), and p/fiber over the injected map; absent it, p RAISES a
#                     clear error. The integrity test (which MAY drive git) supplies the real map.
_READ_CLOCKS: frozenset[Clock] = frozenset({Clock.PROJECTION_EVENT, Clock.LAST_WRITE, Clock.NOW})
_COARSENING_CLOCKS: frozenset[Clock] = frozenset({Clock.COMMIT, Clock.DISTINCT_SNAPSHOT})


